import{R as e,S as t,x as n}from"./vue-Dc_b-yJs.js";import{t as r}from"./app-YrBRqC0l.js";var i=JSON.parse(`{"path":"/rag/chunk.html","title":"RAG Chunk 知识","lang":"zh-CN","frontmatter":{"title":"RAG Chunk 知识"},"readingTime":{"minutes":1.77,"words":532},"git":{"createdTime":1782707484000,"updatedTime":1782715125000,"contributors":[{"name":"GuChenJie","username":"GuChenJie","email":"guchunjie@example.com","commits":2,"avatar":"https://avatars.githubusercontent.com/GuChenJie?v=4","url":"https://github.com/GuChenJie"}]},"filePathRelative":"rag/chunk.md","headers":[]}`),a={name:`chunk.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<p>Chunk 的目标不是“切得越碎越好”，而是让每一段既保留上下文，又方便检索命中。</p><h2 id="一、基础切分" tabindex="-1"><a class="header-anchor" href="#一、基础切分"><span>一、基础切分</span></a></h2><h3 id="_1-固定长度切分" tabindex="-1"><a class="header-anchor" href="#_1-固定长度切分"><span>1. 固定长度切分</span></a></h3><p>最简单的方式，按字符数、词数或 token 数硬切。</p><p><strong>适用场景</strong></p><ul><li>先把系统跑起来</li><li>文档结构不明显</li><li>对稳定性要求高于召回质量</li></ul><h3 id="_2-递归切分" tabindex="-1"><a class="header-anchor" href="#_2-递归切分"><span>2. 递归切分</span></a></h3><p>先按大结构切，再逐层细分，直到满足长度限制。</p><h3 id="_3-基于句子的切分" tabindex="-1"><a class="header-anchor" href="#_3-基于句子的切分"><span>3. 基于句子的切分</span></a></h3><p>按句号、问号、分号等边界切分，再按长度控制合并。</p><h2 id="二、结构切分" tabindex="-1"><a class="header-anchor" href="#二、结构切分"><span>二、结构切分</span></a></h2><h3 id="_1-markdown-切分" tabindex="-1"><a class="header-anchor" href="#_1-markdown-切分"><span>1. Markdown 切分</span></a></h3><p>按标题层级、段落、代码块切分。</p><h3 id="_2-对话式切分" tabindex="-1"><a class="header-anchor" href="#_2-对话式切分"><span>2. 对话式切分</span></a></h3><p>按角色和轮次切分，比如 user / assistant、Q / A。</p><h2 id="三、语义切分" tabindex="-1"><a class="header-anchor" href="#三、语义切分"><span>三、语义切分</span></a></h2><h3 id="_1-语义切分" tabindex="-1"><a class="header-anchor" href="#_1-语义切分"><span>1. 语义切分</span></a></h3><p>根据相邻段落的语义相似度决定是否合并。</p><h3 id="_2-主题切分" tabindex="-1"><a class="header-anchor" href="#_2-主题切分"><span>2. 主题切分</span></a></h3><p>按主题聚类或主题变化点切分。</p><h3 id="_3-基于相似度的段落合并" tabindex="-1"><a class="header-anchor" href="#_3-基于相似度的段落合并"><span>3. 基于相似度的段落合并</span></a></h3><p>先按段落切，再根据相似度和长度阈值合并。</p><h2 id="四、高级切分" tabindex="-1"><a class="header-anchor" href="#四、高级切分"><span>四、高级切分</span></a></h2><h3 id="_1-parent-child-chunk" tabindex="-1"><a class="header-anchor" href="#_1-parent-child-chunk"><span>1. Parent-Child Chunk</span></a></h3><p>把大块内容作为 parent，小块内容作为 child。</p><h3 id="_2-agentic-chunk" tabindex="-1"><a class="header-anchor" href="#_2-agentic-chunk"><span>2. Agentic Chunk</span></a></h3><p>让模型参与判断切分边界。</p><h3 id="_3-自适应切分" tabindex="-1"><a class="header-anchor" href="#_3-自适应切分"><span>3. 自适应切分</span></a></h3><p>根据文档类型自动选择策略。</p><h2 id="五、混合切分" tabindex="-1"><a class="header-anchor" href="#五、混合切分"><span>五、混合切分</span></a></h2><p>混合切分的核心是不要只依赖一种边界。</p><h3 id="常见组合" tabindex="-1"><a class="header-anchor" href="#常见组合"><span>常见组合</span></a></h3><ul><li>Markdown + 固定长度</li><li>语义 + 固定长度</li><li>章节 + 句子</li><li>Parent-Child + 结构切分</li></ul><h3 id="适合什么情况" tabindex="-1"><a class="header-anchor" href="#适合什么情况"><span>适合什么情况</span></a></h3><ul><li>你希望 chunk 既稳定又不太碎</li><li>文档类型不统一</li><li>召回效果比实现简单更重要</li></ul><h2 id="六、选型建议" tabindex="-1"><a class="header-anchor" href="#六、选型建议"><span>六、选型建议</span></a></h2><ul><li><strong>先上线</strong>：固定长度 / 递归切分</li><li><strong>文档型内容</strong>：Markdown / 章节切分</li><li><strong>问答和对话</strong>：对话切分</li><li><strong>长文和复杂内容</strong>：语义切分</li><li><strong>追求更高质量</strong>：混合切分</li></ul><h2 id="七、和代码实现的关系" tabindex="-1"><a class="header-anchor" href="#七、和代码实现的关系"><span>七、和代码实现的关系</span></a></h2><p>现在项目里的实现可以作为这份知识文档的参考：</p><ul><li><code>src/common/rag/chunk/basic/</code></li><li><code>src/common/rag/chunk/structured/</code></li><li><code>src/common/rag/chunk/semantic/</code></li><li><code>src/common/rag/chunk/hybrid/</code></li></ul><p>后续如果继续补内容，建议按“方法原理 / 适用场景 / 代码实现 / 选型建议”这个顺序展开。</p>`,41)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};